mapper.select:
SELECT n.*, u.username, u.nickname
FROM t_travel_note n LEFT JOIN t_user u ON n.user_id = u.user_id
WHERE n.note_id = #{noteId}

SELECT n.*, u.username, u.nickname FROM t_travel_note n LEFT JOIN t_user u ON n.user_id = u.user_id WHERE n.status = 1
AND n.title LIKE CONCAT('%',#{keyword},'%')
ORDER BY n.create_time DESC LIMIT #{offset}, #{limit}

mapper.update:
UPDATE t_travel_note
update_time = NOW(), title = #{title}, content = #{content}, cover_image = #{coverImage},
WHERE note_id = #{noteId}

